phase1.code:
fun main() {
    // ---- Nullable and non-nullable types ----
    val nonNull: String = "Hello"
    // nonNull = null  // ❌ Compile error!

    val nullable: String? = null  // ✅ Allowed
    val notNull: String? = "World"

    // ---- Safe call operator (?.) ----
    println("Nullable: ${nullable?.length}")   // Prints "null"
    println("Not null: ${notNull?.length}")   // Prints "5"

    // ---- Elvis operator (?:) ----
    val length1 = nullable?.length ?: 0
    val length2 = notNull?.length ?: 0
    println("Length with Elvis: $length1, $length2")

    // ---- Not-null assertion (!!) ----
    // Use with caution! Only when you're sure it's not null
    val text: String? = "Hello"
    val length = text!!.length  // Force unwrap
    println("Forced unwrap length: $length")

    // ---- Safe casting (as?) ----
    val obj: Any? = "Hello"
    val str: String? = obj as? String  // Safe cast
    println("Safe cast result: $str")

    // ---- Let with null safety ----
    val name: String? = "Kotlin-chan"
    name?.let {
        println("Name is not null: $it")
        println("Length: ${it.length}")
    }

    // ---- Scope function with null ----
    val nullName: String? = null
    nullName?.let {
        println("This won't print because name is null")
    } ?: println("Name is null!")

    // ---- Real-world example ----
    fun printLength(text: String?) {
        val len = text?.length ?: 0
        println("Text length: $len")
    }

    printLength("Hello")
    printLength(null)
}

